const React = window.React;
const { useEffect, useMemo, useRef, useState } = React;
import { Responsive, WidthProvider } from "react-grid-layout/legacy";

const ResponsiveGridLayout = WidthProvider(Responsive);

export const DEFAULT_CANVAS_BREAKPOINTS = {
  lg: 1200,
  md: 996,
  sm: 768,
  xs: 480,
  xxs: 0,
};

export const DEFAULT_CANVAS_COLS = {
  lg: 12,
  md: 10,
  sm: 6,
  xs: 4,
  xxs: 2,
};

const DEFAULT_RESIZE_HANDLES = ["s", "w", "e", "n", "sw", "nw", "se", "ne"];

function normalizeGridInteger(value, fallbackValue, {
  min = 0,
  max = Number.MAX_SAFE_INTEGER,
} = {}) {
  const numericValue = Math.round(Number(value));
  if (!Number.isInteger(numericValue)) {
    return fallbackValue;
  }

  return Math.min(max, Math.max(min, numericValue));
}

function normalizeWidgetDefaultSize(size = {}) {
  const w = normalizeGridInteger(size?.w, 4, { min: 1 });
  const h = normalizeGridInteger(size?.h, 5, { min: 1 });
  const minW = normalizeGridInteger(size?.minW, Math.min(w, 2), {
    min: 1,
    max: w,
  });
  const minH = normalizeGridInteger(size?.minH, Math.min(h, 3), {
    min: 1,
    max: h,
  });

  return {
    w,
    h,
    minW,
    minH,
  };
}

function buildAutoPlacement(providers, breakpoint, cols) {
  let cursorX = 0;
  let cursorY = 0;
  let rowHeight = 0;

  return providers.map((provider) => {
    const normalizedSize = normalizeWidgetDefaultSize(provider?.defaultSize);
    const width = Math.min(cols, normalizedSize.w);

    if (cursorX + width > cols) {
      cursorX = 0;
      cursorY += rowHeight;
      rowHeight = 0;
    }

    const item = {
      i: provider.id,
      x: cursorX,
      y: cursorY,
      w: width,
      h: normalizedSize.h,
      minW: Math.min(cols, normalizedSize.minW),
      minH: normalizedSize.minH,
      resizeHandles: DEFAULT_RESIZE_HANDLES,
    };

    cursorX += width;
    rowHeight = Math.max(rowHeight, normalizedSize.h);
    return item;
  });
}

function buildDefaultLayoutsFromProviders(providers, breakpoints, colsByBreakpoint) {
  const layouts = {};

  for (const breakpoint of Object.keys(breakpoints)) {
    const cols = colsByBreakpoint[breakpoint];
    const autoPlacements = buildAutoPlacement(providers, breakpoint, cols);
    const autoPlacementsById = new Map(autoPlacements.map((entry) => [entry.i, entry]));

    layouts[breakpoint] = providers.map((provider) => {
      const placement = provider?.defaultPlacement?.[breakpoint];
      const fallbackItem = autoPlacementsById.get(provider.id);
      const normalizedSize = normalizeWidgetDefaultSize(provider?.defaultSize);
      const minW = normalizeGridInteger(
        placement?.minW,
        fallbackItem.minW,
        { min: 1, max: cols },
      );
      const minH = normalizeGridInteger(
        placement?.minH,
        fallbackItem.minH,
        { min: 1 },
      );
      const w = normalizeGridInteger(
        placement?.w,
        fallbackItem.w,
        { min: minW, max: cols },
      );
      const h = normalizeGridInteger(
        placement?.h,
        fallbackItem.h,
        { min: minH },
      );

      return {
        i: provider.id,
        x: normalizeGridInteger(
          placement?.x,
          fallbackItem.x,
          { min: 0, max: Math.max(0, cols - w) },
        ),
        y: normalizeGridInteger(placement?.y, fallbackItem.y, { min: 0 }),
        w,
        h,
        minW: Math.min(cols, normalizeGridInteger(normalizedSize.minW, minW, { min: 1, max: cols })),
        minH: normalizeGridInteger(normalizedSize.minH, minH, { min: 1 }),
        resizeHandles: DEFAULT_RESIZE_HANDLES,
      };
    });
  }

  return layouts;
}

function buildDefaultWidgetInstances(providers) {
  return providers.map((provider) => ({
    id: provider.id,
    providerId: provider.id,
    config: provider.defaultConfig && typeof provider.defaultConfig === "object"
      ? provider.defaultConfig
      : {},
  }));
}

function normalizeCanvasLayoutItem(item, fallbackItem, cols) {
  const minW = normalizeGridInteger(item?.minW, fallbackItem.minW, {
    min: 1,
    max: cols,
  });
  const minH = normalizeGridInteger(item?.minH, fallbackItem.minH, {
    min: 1,
  });
  const w = normalizeGridInteger(item?.w, fallbackItem.w, {
    min: minW,
    max: cols,
  });
  const h = normalizeGridInteger(item?.h, fallbackItem.h, {
    min: minH,
  });

  return {
    i: fallbackItem.i,
    x: normalizeGridInteger(item?.x, fallbackItem.x, {
      min: 0,
      max: Math.max(0, cols - w),
    }),
    y: normalizeGridInteger(item?.y, fallbackItem.y, {
      min: 0,
    }),
    w,
    h,
    minW,
    minH,
    resizeHandles: DEFAULT_RESIZE_HANDLES,
  };
}

function normalizeCanvasState(source, providers, {
  breakpoints = DEFAULT_CANVAS_BREAKPOINTS,
  colsByBreakpoint = DEFAULT_CANVAS_COLS,
} = {}) {
  const providersById = new Map(providers.map((provider) => [provider.id, provider]));
  const defaultWidgetInstances = buildDefaultWidgetInstances(providers);
  const defaultLayouts = buildDefaultLayoutsFromProviders(providers, breakpoints, colsByBreakpoint);
  const rawState = source && typeof source === "object" ? source : {};
  const rawWidgetInstances = Array.isArray(rawState.widgetInstances) ? rawState.widgetInstances : [];
  const nextWidgetInstances = [];
  const usedInstanceIds = new Set();

  for (const rawInstance of rawWidgetInstances) {
    const providerId = String(rawInstance?.providerId || "").trim();
    const provider = providersById.get(providerId);
    if (!provider) {
      continue;
    }

    const instanceId = String(rawInstance?.id || providerId).trim() || providerId;
    if (usedInstanceIds.has(instanceId)) {
      continue;
    }

    usedInstanceIds.add(instanceId);
    nextWidgetInstances.push({
      id: instanceId,
      providerId,
      config: rawInstance?.config && typeof rawInstance.config === "object"
        ? rawInstance.config
        : {},
    });
  }

  for (const defaultInstance of defaultWidgetInstances) {
    if (usedInstanceIds.has(defaultInstance.id)) {
      continue;
    }

    usedInstanceIds.add(defaultInstance.id);
    nextWidgetInstances.push(defaultInstance);
  }

  const rawLayouts = rawState.layouts && typeof rawState.layouts === "object" ? rawState.layouts : {};
  const layouts = {};

  for (const breakpoint of Object.keys(breakpoints)) {
    const fallbackItems = defaultLayouts[breakpoint].filter((entry) =>
      nextWidgetInstances.some((instance) => instance.id === entry.i),
    );
    const rawItems = Array.isArray(rawLayouts?.[breakpoint]) ? rawLayouts[breakpoint] : [];
    const rawItemsById = new Map(rawItems.map((entry) => [String(entry?.i || ""), entry]));

    layouts[breakpoint] = fallbackItems.map((fallbackItem) =>
      normalizeCanvasLayoutItem(
        rawItemsById.get(fallbackItem.i),
        fallbackItem,
        colsByBreakpoint[breakpoint],
      ));
  }

  return {
    version: 1,
    widgetInstances: nextWidgetInstances,
    layouts,
  };
}

function getCanvasLayoutsSignature(layouts) {
  return JSON.stringify(layouts);
}

export function createCanvasStateFromLegacyLayouts(legacyLayouts, providers, options = {}) {
  const normalizedDefaultState = normalizeCanvasState(null, providers, options);
  const rawLegacyLayouts = legacyLayouts && typeof legacyLayouts === "object" ? legacyLayouts : {};
  const nextLayouts = {};

  for (const breakpoint of Object.keys(normalizedDefaultState.layouts)) {
    const fallbackItems = normalizedDefaultState.layouts[breakpoint];
    const rawItems = Array.isArray(rawLegacyLayouts?.[breakpoint]) ? rawLegacyLayouts[breakpoint] : [];
    const rawItemsById = new Map(rawItems.map((entry) => [String(entry?.i || ""), entry]));

    nextLayouts[breakpoint] = fallbackItems.map((fallbackItem) =>
      normalizeCanvasLayoutItem(
        rawItemsById.get(fallbackItem.i),
        fallbackItem,
        (options.colsByBreakpoint || DEFAULT_CANVAS_COLS)[breakpoint],
      ));
  }

  return {
    ...normalizedDefaultState,
    layouts: nextLayouts,
  };
}

export function CanvasWorkspace({
  providers = [],
  canvasState = null,
  onPersistCanvasState,
  editMode = false,
  widgetContext = null,
  onPersistError,
  gridClassName = "nexusPluginCanvas__grid",
  itemClassName = "nexusPluginCanvas__item",
  widgetClassName = "",
  editingClassName = "is-editing",
  editOverlayClassName = "nexusPluginCanvas__editOverlay",
  draggableCancel = "button, input, select, textarea, label, canvas",
  breakpoints = DEFAULT_CANVAS_BREAKPOINTS,
  cols = DEFAULT_CANVAS_COLS,
  rowHeight = 30,
  margin = [12, 12],
  containerPadding = [0, 0],
  persistDebounceMs = 120,
}) {
  const normalizedCanvasState = useMemo(
    () => normalizeCanvasState(canvasState, providers, { breakpoints, colsByBreakpoint: cols }),
    [breakpoints, canvasState, cols, providers],
  );
  const persistedLayoutsSignature = useMemo(
    () => getCanvasLayoutsSignature(normalizedCanvasState.layouts),
    [normalizedCanvasState.layouts],
  );
  const [renderedLayouts, setRenderedLayouts] = useState(() => normalizedCanvasState.layouts);
  const [gridMounted, setGridMounted] = useState(false);
  const persistedLayoutsRef = useRef(normalizedCanvasState.layouts);
  const persistedLayoutsSignatureRef = useRef(persistedLayoutsSignature);
  const persistTimerRef = useRef(null);
  const appliedPersistedLayoutsSignatureRef = useRef(persistedLayoutsSignature);
  const providersById = useMemo(
    () => new Map(providers.map((provider) => [provider.id, provider])),
    [providers],
  );

  useEffect(() => {
    setGridMounted(true);
  }, []);

  useEffect(() => {
    if (appliedPersistedLayoutsSignatureRef.current === persistedLayoutsSignature) {
      return;
    }

    appliedPersistedLayoutsSignatureRef.current = persistedLayoutsSignature;
    persistedLayoutsRef.current = normalizedCanvasState.layouts;
    persistedLayoutsSignatureRef.current = persistedLayoutsSignature;
    setRenderedLayouts((currentValue) => (
      getCanvasLayoutsSignature(currentValue) === persistedLayoutsSignature
        ? currentValue
        : normalizedCanvasState.layouts
    ));
  }, [normalizedCanvasState.layouts, persistedLayoutsSignature]);

  useEffect(() => {
    return () => {
      if (persistTimerRef.current !== null) {
        window.clearTimeout(persistTimerRef.current);
      }
    };
  }, []);

  const commitLayouts = (allLayouts) => {
    const nextCanvasState = normalizeCanvasState(
      {
        ...normalizedCanvasState,
        layouts: allLayouts,
      },
      providers,
      { breakpoints, colsByBreakpoint: cols },
    );
    const nextSignature = getCanvasLayoutsSignature(nextCanvasState.layouts);

    persistedLayoutsRef.current = nextCanvasState.layouts;
    persistedLayoutsSignatureRef.current = nextSignature;
    setRenderedLayouts(nextCanvasState.layouts);

    if (nextSignature === persistedLayoutsSignature) {
      return;
    }

    if (persistTimerRef.current !== null) {
      window.clearTimeout(persistTimerRef.current);
    }

    persistTimerRef.current = window.setTimeout(() => {
      persistTimerRef.current = null;
      Promise.resolve(onPersistCanvasState?.(nextCanvasState)).catch((error) => {
        onPersistError?.(error);
      });
    }, persistDebounceMs);
  };

  const handleLayoutChange = (_currentLayout, allLayouts) => {
    const nextCanvasState = normalizeCanvasState(
      {
        ...normalizedCanvasState,
        layouts: allLayouts,
      },
      providers,
      { breakpoints, colsByBreakpoint: cols },
    );
    const nextSignature = getCanvasLayoutsSignature(nextCanvasState.layouts);

    if (nextSignature === persistedLayoutsSignatureRef.current) {
      return;
    }

    persistedLayoutsRef.current = nextCanvasState.layouts;
    persistedLayoutsSignatureRef.current = nextSignature;
  };

  return (
    <ResponsiveGridLayout
      className={gridClassName}
      layouts={renderedLayouts}
      breakpoints={breakpoints}
      cols={cols}
      rowHeight={rowHeight}
      margin={margin}
      containerPadding={containerPadding}
      measureBeforeMount={false}
      autoSize
      resizeHandles={DEFAULT_RESIZE_HANDLES}
      compactType={null}
      preventCollision={true}
      useCSSTransforms={gridMounted}
      isDraggable={editMode}
      isResizable={editMode}
      draggableHandle={`.${editOverlayClassName}`}
      draggableCancel={draggableCancel}
      onLayoutChange={handleLayoutChange}
      onDragStop={(_currentLayout, allLayouts) => commitLayouts(allLayouts)}
      onResizeStop={(_currentLayout, allLayouts) => commitLayouts(allLayouts)}
    >
      {normalizedCanvasState.widgetInstances.map((instance) => {
        const provider = providersById.get(instance.providerId);
        if (!provider) {
          return null;
        }

        const WidgetComponent = provider.component;
        return (
          <div
            key={instance.id}
            className={[
              itemClassName,
              widgetClassName,
              editMode ? editingClassName : "",
            ].filter(Boolean).join(" ")}
          >
            <WidgetComponent
              provider={provider}
              instance={instance}
              editMode={editMode}
              widgetContext={widgetContext}
            />
            {editMode ? <div className={editOverlayClassName} aria-hidden="true" /> : null}
          </div>
        );
      })}
    </ResponsiveGridLayout>
  );
}
