import MarkdownIt from "markdown-it";

function normalizeWikiTarget(value) {
  const raw = String(value || "").trim();
  if (!raw || raw.includes("|")) {
    return null;
  }

  return {
    target: raw,
    label: raw,
  };
}

function wikilinkPlugin(md) {
  md.inline.ruler.before("emphasis", "wikilink", (state, silent) => {
    const start = state.pos;

    if (state.src.charCodeAt(start) !== 0x5b || state.src.charCodeAt(start + 1) !== 0x5b) {
      return false;
    }

    const end = state.src.indexOf("]]", start + 2);
    if (end < 0) {
      return false;
    }

    const body = state.src.slice(start + 2, end);
    const normalized = normalizeWikiTarget(body);
    if (!normalized) {
      return false;
    }

    const { target, label } = normalized;

    if (!target) {
      return false;
    }

    if (!silent) {
      const tokenOpen = state.push("wikilink_open", "a", 1);
      tokenOpen.attrs = [
        ["href", "#"],
        ["data-nexus-wikilink", target],
        ["class", "markdown-engine-wikilink"],
      ];

      const tokenText = state.push("text", "", 0);
      tokenText.content = label;

      state.push("wikilink_close", "a", -1);
    }

    state.pos = end + 2;
    return true;
  });

  md.renderer.rules.wikilink_open = (tokens, index, options, env, self) =>
    self.renderToken(tokens, index, options);
  md.renderer.rules.wikilink_close = (tokens, index, options, env, self) =>
    self.renderToken(tokens, index, options);
}

function taskListPlugin(md) {
  md.core.ruler.after("inline", "nexus-task-list", (state) => {
    state.tokens.forEach((token, index) => {
      if (token.type !== "inline" || !Array.isArray(token.children) || !token.children.length) {
        return;
      }

      const paragraphToken = state.tokens[index - 1];
      const listItemToken = state.tokens[index - 2];
      if (paragraphToken?.type !== "paragraph_open" || listItemToken?.type !== "list_item_open") {
        return;
      }

      const firstTextToken = token.children.find((child) => child.type === "text" && child.content);
      if (!firstTextToken) {
        return;
      }

      const match = firstTextToken.content.match(/^\[([ xX])\]\s+/);
      if (!match) {
        return;
      }

      const checked = match[1].toLowerCase() === "x";
      firstTextToken.content = firstTextToken.content.slice(match[0].length);
      listItemToken.attrJoin("class", "markdown-task-item");

      const checkboxToken = new state.Token("html_inline", "", 0);
      const sourceLine = listItemToken.map?.[0] ?? -1;
      checkboxToken.content = [
        "<label class=\"markdown-task-checkbox\">",
        `<input type="checkbox" class="markdown-task-checkboxInput" data-source-line="${sourceLine}" ${checked ? "checked" : ""}>`,
        "<span class=\"markdown-task-checkboxBox\" aria-hidden=\"true\"></span>",
        "</label>",
      ].join("");

      token.children.unshift(checkboxToken);
    });
  });
}

function highlightPlugin(md) {
  md.inline.ruler.before("emphasis", "nexus-highlight", (state, silent) => {
    const start = state.pos;

    if (state.src.charCodeAt(start) !== 0x3d || state.src.charCodeAt(start + 1) !== 0x3d) {
      return false;
    }

    const end = state.src.indexOf("==", start + 2);
    if (end < 0 || end === start + 2) {
      return false;
    }

    if (!silent) {
      state.push("mark_open", "mark", 1);

      const tokenText = state.push("text", "", 0);
      tokenText.content = state.src.slice(start + 2, end);

      state.push("mark_close", "mark", -1);
    }

    state.pos = end + 2;
    return true;
  });
}

function sourceBreaksPlugin(md) {
  md.core.ruler.after("block", "nexus-source-breaks", (state) => {
    const insertions = [];
    const lastEndByLevel = new Map();
    const sourceLines = state.src.replace(/\r\n/g, "\n").split("\n");

    function getNormalizedEndLine(token) {
      if (!Array.isArray(token.map)) {
        return null;
      }

      const [startLine, rawEndLine] = token.map;
      let endLine = rawEndLine;

      while (endLine > startLine) {
        const line = sourceLines[endLine - 1];
        if (typeof line !== "string" || line.trim()) {
          break;
        }

        endLine -= 1;
      }

      return endLine;
    }

    state.tokens.forEach((token, index) => {
      if (
        !token.block ||
        !Array.isArray(token.map) ||
        token.nesting === -1 ||
        token.type === "inline"
      ) {
        return;
      }

      const [startLine] = token.map;
      const endLine = getNormalizedEndLine(token);
      if (!Number.isInteger(endLine)) {
        return;
      }

      const level = token.level;

      Array.from(lastEndByLevel.keys()).forEach((key) => {
        if (key > level) {
          lastEndByLevel.delete(key);
        }
      });

      const previousEnd = lastEndByLevel.get(level);
      if (Number.isInteger(previousEnd)) {
        const gap = startLine - previousEnd;

        for (let offset = 0; offset < gap; offset += 1) {
          const breakToken = new state.Token("html_block", "", 0);
          breakToken.block = true;
          breakToken.level = level;
          breakToken.map = [previousEnd + offset, previousEnd + offset + 1];
          breakToken.meta = {
            sourceBreak: true,
          };
          breakToken.content = "<br class=\"markdown-engine-sourceBreak\">\n";
          insertions.push({ index, token: breakToken });
        }
      }

      lastEndByLevel.set(level, endLine);
    });

    for (let index = insertions.length - 1; index >= 0; index -= 1) {
      const insertion = insertions[index];
      state.tokens.splice(insertion.index, 0, insertion.token);
    }
  });
}

function htmlBlockWrapperPlugin(md) {
  const defaultHtmlBlockRenderer =
    md.renderer.rules.html_block ??
    ((tokens, index) => tokens[index]?.content || "");

  md.renderer.rules.html_block = (tokens, index, options, env, self) => {
    const token = tokens[index];
    if (token?.meta?.sourceBreak) {
      return token.content || "";
    }

    return [
      "<div class=\"markdown-engine-htmlBlock\">",
      defaultHtmlBlockRenderer(tokens, index, options, env, self),
      "</div>",
    ].join("");
  };
}

function enhanceRenderedHtml(html) {
  const parser = new DOMParser();
  const documentFragment = parser.parseFromString(`<div class="markdown-engine-renderRoot">${html}</div>`, "text/html");
  const root = documentFragment.body.firstElementChild;

  if (!root) {
    return html;
  }

  root.querySelectorAll("blockquote").forEach((blockquote) => {
    const firstParagraph = blockquote.firstElementChild;
    if (!firstParagraph || firstParagraph.tagName !== "P") {
      return;
    }

    const paragraphSegments = firstParagraph.innerHTML
      .split(/<br\s*\/?>/i)
      .map((segment) => segment.trim())
      .filter(Boolean);
    const headerProbe = documentFragment.createElement("span");
    headerProbe.innerHTML = paragraphSegments[0] || firstParagraph.innerHTML;
    const headerText = headerProbe.textContent?.trim() || "";
    const calloutMatch = headerText.match(/^\[!([A-Za-z]+)\](?:\s+(.*))?$/);
    if (!calloutMatch) {
      return;
    }

    const [, rawType, rawTitle] = calloutMatch;
    const type = rawType.toLowerCase();
    const title = rawTitle?.trim() || rawType.charAt(0).toUpperCase() + rawType.slice(1).toLowerCase();
    const callout = documentFragment.createElement("section");
    callout.className = `markdown-callout markdown-callout--${type}`;

    const header = documentFragment.createElement("div");
    header.className = "markdown-callout-header";
    header.textContent = title;

    const body = documentFragment.createElement("div");
    body.className = "markdown-callout-body";

    if (paragraphSegments.length > 1) {
      const bodyParagraph = documentFragment.createElement("p");
      bodyParagraph.innerHTML = paragraphSegments.slice(1).join("<br>");
      body.appendChild(bodyParagraph);
    }

    Array.from(blockquote.children).slice(1).forEach((child) => {
      body.appendChild(child.cloneNode(true));
    });

    callout.appendChild(header);
    if (body.childNodes.length) {
      callout.appendChild(body);
    }

    blockquote.replaceWith(callout);
  });

  return root.innerHTML;
}

const markdown = new MarkdownIt({
  breaks: true,
  html: true,
  linkify: true,
})
  .use(sourceBreaksPlugin)
  .use(htmlBlockWrapperPlugin)
  .use(highlightPlugin)
  .use(wikilinkPlugin)
  .use(taskListPlugin);

export function renderMarkdown(markdownText) {
  return enhanceRenderedHtml(markdown.render(markdownText || ""));
}

export function toggleMarkdownTaskLine(source, lineIndex, checked) {
  const text = String(source || "");
  const lineBreak = text.includes("\r\n") ? "\r\n" : "\n";
  const lines = text.replace(/\r\n/g, "\n").split("\n");
  const currentLine = lines[lineIndex];

  if (typeof currentLine !== "string") {
    return text;
  }

  const nextLine = currentLine.replace(/^(\s*[-*+]\s+)\[([ xX])\](\s+)/, `$1[${checked ? "x" : " "}]$3`);
  if (nextLine === currentLine) {
    return text;
  }

  lines[lineIndex] = nextLine;
  return lines.join(lineBreak);
}
