import { cx } from "./cx.js";

export function Button({
  className = "",
  tone = "secondary",
  iconOnly = false,
  children,
  ...props
}) {
  return (
    <button
      {...props}
      className={cx(
        "nexus-ui-button",
        tone !== "secondary" && `nexus-ui-button--${tone}`,
        iconOnly && "nexus-ui-button--icon",
        className,
      )}
    >
      {children}
    </button>
  );
}

export function IconButton({ className = "", tone = "secondary", title = "", children, ...props }) {
  return (
    <Button
      {...props}
      className={className}
      tone={tone}
      iconOnly
      title={title}
      aria-label={props["aria-label"] || title || undefined}
    >
      {children}
    </Button>
  );
}

export function SegmentedControl({
  className = "",
  options = [],
  value,
  onChange,
  ariaLabel = "Selector",
}) {
  return (
    <div className={cx("nexus-ui-segmented", className)} role="tablist" aria-label={ariaLabel}>
      {options.map((option) => {
        const optionValue = option.value;
        const active = optionValue === value;

        return (
          <button
            key={optionValue}
            type="button"
            role="tab"
            aria-selected={active}
            className={cx("nexus-ui-segmented__button", active && "is-active")}
            onClick={() => onChange?.(optionValue)}
          >
            {option.icon ? <span className="nexus-ui-segmented__icon">{option.icon}</span> : null}
            <span>{option.label}</span>
          </button>
        );
      })}
    </div>
  );
}
