import yaml from "js-yaml";

function isPlainObject(value) {
  return value != null && typeof value === "object" && !Array.isArray(value);
}

function normalizeSource(source) {
  return String(source || "").replace(/\r\n/g, "\n");
}

function stringifyMetadataValue(value) {
  if (value == null) {
    return "";
  }

  if (Array.isArray(value)) {
    if (value.every((entry) => entry == null || ["string", "number", "boolean"].includes(typeof entry))) {
      return value.map((entry) => String(entry ?? "")).join(", ");
    }

    return yaml.dump(value, {
      lineWidth: 120,
      noRefs: true,
      sortKeys: false,
    }).trim();
  }

  if (isPlainObject(value)) {
    return yaml.dump(value, {
      lineWidth: 120,
      noRefs: true,
      sortKeys: false,
    }).trim();
  }

  return String(value);
}

function flattenMetadataValue(value, keyPath, entries) {
  if (Array.isArray(value)) {
    entries.push({
      key: keyPath,
      value: stringifyMetadataValue(value),
    });
    return;
  }

  if (!isPlainObject(value)) {
    entries.push({
      key: keyPath,
      value: stringifyMetadataValue(value),
    });
    return;
  }

  const objectEntries = Object.entries(value);
  if (!objectEntries.length) {
    entries.push({
      key: keyPath,
      value: "{}",
    });
    return;
  }

  for (const [key, childValue] of objectEntries) {
    flattenMetadataValue(childValue, keyPath ? `${keyPath}.${key}` : key, entries);
  }
}

function buildMetadataEntries(frontmatter) {
  if (!isPlainObject(frontmatter)) {
    return [];
  }

  const entries = [];
  for (const [key, value] of Object.entries(frontmatter)) {
    flattenMetadataValue(value, key, entries);
  }
  return entries;
}

function parseFrontmatterLine(line, lineFrom, index, endLineIndex) {
  const trimmed = line.trim();

  if (trimmed === "---" || trimmed === "...") {
    return {
      from: lineFrom,
      to: lineFrom + line.length,
      keyFrom: null,
      keyTo: null,
      separatorFrom: null,
      separatorTo: null,
      valueFrom: null,
      valueTo: null,
      kind: "delimiter",
      isFirst: index === 0,
      isLast: index === endLineIndex,
    };
  }

  const lineMatch = line.match(/^(\s*[A-Za-z0-9_-][A-Za-z0-9_\-\s]*)\s*:/);
  if (!lineMatch) {
    return {
      from: lineFrom,
      to: lineFrom + line.length,
      keyFrom: null,
      keyTo: null,
      separatorFrom: null,
      separatorTo: null,
      valueFrom: null,
      valueTo: null,
      kind: "content",
      isFirst: index === 0,
      isLast: index === endLineIndex,
    };
  }

  const key = lineMatch[1];
  const separatorIndex = line.indexOf(":");
  const remainder = line.slice(separatorIndex + 1);
  const valueOffset = remainder.search(/\S/);
  const valueFrom = valueOffset < 0 ? null : lineFrom + separatorIndex + 1 + valueOffset;

  return {
    from: lineFrom,
    to: lineFrom + line.length,
    keyFrom: lineFrom,
    keyTo: lineFrom + key.length,
    separatorFrom: lineFrom + separatorIndex,
    separatorTo: lineFrom + separatorIndex + 1,
    valueFrom,
    valueTo: valueFrom == null ? null : lineFrom + line.length,
    kind: "content",
    isFirst: index === 0,
    isLast: index === endLineIndex,
  };
}

export function extractMarkdownMetadata(source) {
  const text = normalizeSource(source);
  const lines = text.split("\n");

  if (!lines.length || lines[0].trim() !== "---") {
    return {
      metadata: [],
      metadataObject: {},
      frontmatter: {},
      body: text,
      bodyStartLine: 0,
      hasFrontmatter: false,
      parseError: null,
    };
  }

  let delimiterLineIndex = -1;
  for (let index = 1; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (trimmed === "---" || trimmed === "...") {
      delimiterLineIndex = index;
      break;
    }
  }

  if (delimiterLineIndex < 0) {
    return {
      metadata: [],
      metadataObject: {},
      frontmatter: {},
      body: text,
      bodyStartLine: 0,
      hasFrontmatter: false,
      parseError: null,
    };
  }

  const rawFrontmatter = lines.slice(1, delimiterLineIndex).join("\n");
  const body = lines.slice(delimiterLineIndex + 1).join("\n");

  try {
    const parsed = rawFrontmatter.trim() ? yaml.load(rawFrontmatter) : {};
    const frontmatter = isPlainObject(parsed) ? parsed : {};
    return {
      metadata: buildMetadataEntries(frontmatter),
      metadataObject: frontmatter,
      frontmatter,
      body,
      bodyStartLine: delimiterLineIndex + 1,
      hasFrontmatter: true,
      parseError: null,
    };
  } catch (error) {
    return {
      metadata: [],
      metadataObject: {},
      frontmatter: {},
      body: text,
      bodyStartLine: 0,
      hasFrontmatter: false,
      parseError: error instanceof Error ? error.message : "No se pudo parsear el frontmatter YAML.",
    };
  }
}

export function getMarkdownMetadataRanges(source) {
  const text = normalizeSource(source);
  const lines = text.split("\n");

  if (!lines.length || lines[0].trim() !== "---") {
    return [];
  }

  let delimiterLineIndex = -1;
  for (let index = 1; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (trimmed === "---" || trimmed === "...") {
      delimiterLineIndex = index;
      break;
    }
  }

  if (delimiterLineIndex < 0) {
    return [];
  }

  let offset = 0;
  const ranges = [];

  for (let index = 0; index <= delimiterLineIndex; index += 1) {
    const line = lines[index];
    ranges.push(parseFrontmatterLine(line, offset, index, delimiterLineIndex));
    offset += line.length + 1;
  }

  return ranges;
}

export function getMarkdownDefaultView(source) {
  const metadata = extractMarkdownMetadata(source).frontmatter;
  const defaultView = metadata?.nexus?.defaultView;
  return String(defaultView || "").trim().toLowerCase() === "read" ? "read" : "live";
}
